module FlowStatus =
  struct
    type nonrec t =
      | Failed 
      | Prepared 
      | Preparing 
      | NotPrepared 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | Failed -> "Failed"
      | Prepared -> "Prepared"
      | Preparing -> "Preparing"
      | NotPrepared -> "NotPrepared"
      | Non_static_id s -> s
    let of_string =
      function
      | "Failed" -> Failed
      | "Prepared" -> Prepared
      | "Preparing" -> Preparing
      | "NotPrepared" -> NotPrepared
      | x -> Non_static_id x
